const start = $input.first().json || {};
const tool = start.tool_input || {};
return [{ json: {
  action: String(tool.action || start.action || ''),
  order_id: String(tool.order_id || start.order_id || ''),
  chat_id: String(tool.chat_id || start.chat_id || ''),
  issue_type: String(tool.issue_type || start.issue_type || ''),
  message: String(start.message || tool.message || ''),
  button_id: String(start.button_id || ''),
  original: start,
} }];

const d = $('Normalize Feedback Input').first().json || {};
return [{
  json: {
    chat_id: String(d.chat_id || ''),
    customer_ui_state: 'TRACKING',
    message_type: 'button',
    body_text: 'Thanks for the feedback.\n\nGlad your order went well.',
    buttons: [
      { id: 'track_order', title: 'Track Order' },
      { id: 'new_order', title: 'Shop Again' },
    ],
  },
}];

const d = $('Normalize Feedback Input').first().json || {};
const orderId = String(d.order_id || '');
return [{
  json: {
    chat_id: String(d.chat_id || ''),
    customer_ui_state: 'FEEDBACK_REASON_PICKER',
    message_type: 'list',
    body_text: 'Report an issue\n\nWhat went wrong with order #' + orderId + '?',
    list_sections: [{
      title: 'Select a reason',
      rows: [
        { id: 'issue_wrong_items__' + orderId, title: 'Wrong items', description: 'You received a different item' },
        { id: 'issue_quality__' + orderId, title: 'Quality issue', description: 'The item was damaged or not fresh' },
        { id: 'issue_late__' + orderId, title: 'Late delivery', description: 'The order arrived too late' },
      ],
    }],
  },
}];

const d = $('Normalize Feedback Input').first().json || {};
const labels = {
  wrong_items: 'wrong items',
  quality_issue: 'a quality issue',
  late_delivery: 'a late delivery',
};
const issueType = labels[d.issue_type] || 'an issue';
return [{
  json: {
    chat_id: String(d.chat_id || ''),
    customer_ui_state: 'FEEDBACK_DETAIL_PENDING',
    message_type: 'button',
    body_text: 'Sorry about ' + issueType + '.\n\nPlease share one short message so we can help the store review it.',
    buttons: [
      { id: 'track_order', title: 'Track Order' },
      { id: 'new_order', title: 'Shop Again' },
    ],
  },
}];

const input = $('Normalize Feedback Input').first().json || {};
const ctx = $('Issue Text: Get Order Context').first().json || {};
const issueLabels = {
  wrong_items: 'Wrong items',
  quality_issue: 'Quality issue',
  late_delivery: 'Late delivery',
};
const issueKey = String(ctx.issue_type || input.issue_type || '');
const issueLabel = issueLabels[issueKey] || 'Customer issue';
const issueText = String(input.message || '').trim() || 'No detail provided';
const storeName = String(ctx.store_name || 'your store');
return [{
  json: {
    chat_id: String(ctx.owner_whatsapp_number || ''),
    message_type: 'text',
    body_text:
      'Customer issue reported\n\n' +
      'Store: ' + storeName + '\n' +
      'Order: ' + String(input.order_id || '') + '\n' +
      'Customer: ' + String(input.chat_id || '') + '\n' +
      'Issue: ' + issueLabel + '\n' +
      'Details: ' + issueText,
  },
}];

const d = $('Normalize Feedback Input').first().json || {};
